+/// Typed `clock_nanosleep` helper over Linux `timespec`.
+///
+/// # Safety
+///
+/// `rem` may be null or must point to writable `Timespec` storage.
+#[inline]
+#[allow(unsafe_code)]
+pub unsafe fn sys_clock_nanosleep_spec(
+    clock_id: i32,
+    flags: i32,
+    req: &Timespec,
+    rem: *mut Timespec,
+) -> Result<(), i32> {
+    unsafe {
+        sys_clock_nanosleep(
+            clock_id,
+            flags,
+            (req as *const Timespec).cast::<u8>(),
+            rem.cast::<u8>(),
+        )
+    }
+}
